1	export type Cell = [number, number];
2	
3	const survives = (liveNeighbors: number): boolean =>
4	  liveNeighbors === 2 || liveNeighbors === 3;
5	
6	const isBorn = (liveNeighbors: number): boolean => liveNeighbors === 3;
7	
8	const isLive = (cell: Cell, liveCells: Cell[]): boolean =>
9	  liveCells.some(([x, y]) => x === cell[0] && y === cell[1]);
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] => [
12	  [x - 1, y - 1],
13	  [x, y - 1],
14	  [x + 1, y - 1],
15	  [x - 1, y],
16	  [x + 1, y],
17	  [x - 1, y + 1],
18	  [x, y + 1],
19	  [x + 1, y + 1],
20	];
21	
22	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
23	  neighborsOf(cell).filter((neighbor) => isLive(neighbor, liveCells)).length;
24	
25	const uniqueCells = (cells: Cell[]): Cell[] => [
26	  ...new Map(cells.map((cell) => [`${cell[0]},${cell[1]}`, cell])).values(),
27	];
28	
29	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
30	  const survivors = liveCells.filter((cell) =>
31	    survives(countLiveNeighbors(cell, liveCells)),
32	  );
33	  const births = uniqueCells(liveCells.flatMap(neighborsOf)).filter(
34	    (cell) =>
35	      !isLive(cell, liveCells) && isBorn(countLiveNeighbors(cell, liveCells)),
36	  );
37	  return [...survivors, ...births];
38	};
