1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Game of Life - nextGeneration", () => {
6	  it("should kill a single live cell (underpopulation: 0 neighbors)", () => {
7	    expect(nextGeneration([[0, 0]])).toEqual([]);
8	  });
9	  it("should kill two adjacent live cells (underpopulation: 1 neighbor each)", () => {
10	    expect(
11	      nextGeneration([
12	        [0, 1],
13	        [1, 1],
14	      ]),
15	    ).toEqual([]);
16	  });
17	  it("should keep a live cell with 2 live neighbors alive (survival)", () => {
18	    const result = nextGeneration([
19	      [0, 0],
20	      [1, 1],
21	      [2, 2],
22	    ]);
23	    expect(result.sort()).toEqual([[1, 1]]);
24	  });
25	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
26	    // Ring pattern ###/.#./### — center cell (1,1) has 6 live neighbors
27	    const ring: Array<[number, number]> = [
28	      [0, 0],
29	      [1, 0],
30	      [2, 0],
31	      [1, 1],
32	      [0, 2],
33	      [1, 2],
34	      [2, 2],
35	    ];
36	    expect(nextGeneration(ring)).not.toContainEqual([1, 1]);
37	  });
38	  it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
39	    // ##./#.. → ##./##. — (1,1) is born; all three live cells survive
40	    const result = nextGeneration([
41	      [0, 0],
42	      [1, 0],
43	      [0, 1],
44	    ]);
45	    expect(result.sort()).toEqual(
46	      [
47	        [0, 0],
48	        [1, 0],
49	        [0, 1],
50	        [1, 1],
51	      ].sort(),
52	    );
53	  });
54	  it("should keep a block still life unchanged", () => {
55	    const block: Array<[number, number]> = [
56	      [0, 0],
57	      [1, 0],
58	      [0, 1],
59	      [1, 1],
60	    ];
61	    expect(nextGeneration(block).sort()).toEqual([...block].sort());
62	  });
63	  it("should oscillate a vertical blinker to a horizontal blinker (negative coordinates)", () => {
64	    const result = nextGeneration([
65	      [0, 0],
66	      [0, 1],
67	      [0, 2],
68	    ]);
69	    expect(result.sort()).toEqual(
70	      [
71	        [-1, 1],
72	        [0, 1],
73	        [1, 1],
74	      ].sort(),
75	    );
76	  });
77	});
